'use client';

import { useState } from 'react';

interface CSVRow {
  [key: string]: string;
}

export default function CSVImportButton() {
  const [csvData, setCsvData] = useState<CSVRow[]>([]);
  const [headers, setHeaders] = useState<string[]>([]);
  const [isLoading, setIsLoading] = useState(false);

  const parseCSV = (text: string): CSVRow[] => {
    const lines = text.trim().split('\n');
    if (lines.length === 0) return [];

    const headers = lines[0].split(',').map(h => h.trim().replace(/"/g, ''));
    setHeaders(headers);

    const rows = lines.slice(1).map(line => {
      const values = line.split(',').map(v => v.trim().replace(/"/g, ''));
      const row: CSVRow = {};
      headers.forEach((header, index) => {
        row[header] = values[index] || '';
      });
      return row;
    });

    return rows;
  };

  const handleFileUpload = async (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    setIsLoading(true);
    try {
      const text = await file.text();
      const parsed = parseCSV(text);
      setCsvData(parsed);
    } catch (error) {
      console.error('Error parsing CSV:', error);
      alert('Error parsing CSV file');
    } finally {
      setIsLoading(false);
    }
  };

  const clearData = () => {
    setCsvData([]);
    setHeaders([]);
  };

  return (
    <div className="w-full max-w-6xl mx-auto p-6 bg-white border border-gray-200 rounded-lg shadow-sm">
      <div className="flex items-center gap-4 mb-6">
        <label className="cursor-pointer bg-blue-600 hover:bg-blue-700 text-white px-4 py-2 rounded-md transition-colors duration-200 flex items-center gap-2">
          <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M7 16a4 4 0 01-.88-7.903A5 5 0 1115.9 6L16 6a5 5 0 011 9.9M15 13l-3-3m0 0l-3 3m3-3v12" />
          </svg>
          {isLoading ? 'Loading...' : 'Import CSV'}
          <input
            type="file"
            accept=".csv"
            onChange={handleFileUpload}
            className="hidden"
            disabled={isLoading}
          />
        </label>

        {csvData.length > 0 && (
          <button
            onClick={clearData}
            className="bg-gray-500 hover:bg-gray-600 text-white px-4 py-2 rounded-md transition-colors duration-200"
          >
            Clear Data
          </button>
        )}
      </div>

      {csvData.length > 0 && (
        <div className="space-y-4">
          <div className="flex items-center justify-between">
            <h3 className="text-lg font-semibold text-gray-800">
              CSV Data ({csvData.length} rows)
            </h3>
          </div>

          <div className="overflow-x-auto border border-gray-200 rounded-md">
            <table className="min-w-full divide-y divide-gray-200">
              <thead className="bg-gray-50">
                <tr>
                  {headers.map((header, index) => (
                    <th
                      key={index}
                      className="px-4 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider"
                    >
                      {header}
                    </th>
                  ))}
                </tr>
              </thead>
              <tbody className="bg-white divide-y divide-gray-200">
                {csvData.slice(0, 100).map((row, rowIndex) => (
                  <tr key={rowIndex} className="hover:bg-gray-50">
                    {headers.map((header, colIndex) => (
                      <td
                        key={colIndex}
                        className="px-4 py-3 whitespace-nowrap text-sm text-gray-900"
                      >
                        {row[header]}
                      </td>
                    ))}
                  </tr>
                ))}
              </tbody>
            </table>
            {csvData.length > 100 && (
              <div className="px-4 py-3 bg-gray-50 text-sm text-gray-500 text-center">
                Showing first 100 rows of {csvData.length} total rows
              </div>
            )}
          </div>
        </div>
      )}
    </div>
  );
}

'use client';

import { useState, useEffect } from 'react';

interface StockData {
  date: string;
  price: number;
}

// Simulated NVIDIA stock data for the last 6 months
const generateNvidiaData = (): StockData[] => {
  const data: StockData[] = [];
  const today = new Date();
  const sixMonthsAgo = new Date(today);
  sixMonthsAgo.setMonth(today.getMonth() - 6);

  // Base price around $400-500 range with realistic fluctuations
  let currentPrice = 420;
  const days = Math.floor((today.getTime() - sixMonthsAgo.getTime()) / (1000 * 60 * 60 * 24));

  for (let i = 0; i <= days; i++) {
    const date = new Date(sixMonthsAgo);
    date.setDate(date.getDate() + i);

    // Add realistic price movement
    const volatility = (Math.random() - 0.5) * 20;
    const trend = (i / days) * 80; // Overall upward trend
    currentPrice = Math.max(300, currentPrice + volatility + (trend / days));

    data.push({
      date: date.toISOString().split('T')[0],
      price: Math.round(currentPrice * 100) / 100
    });
  }

  return data;
};

export default function NvidiaChart() {
  const [data, setData] = useState<StockData[]>([]);
  const [hoveredPoint, setHoveredPoint] = useState<StockData | null>(null);

  useEffect(() => {
    setData(generateNvidiaData());
  }, []);

  if (data.length === 0) return <div className="p-8">Loading chart...</div>;

  const maxPrice = Math.max(...data.map(d => d.price));
  const minPrice = Math.min(...data.map(d => d.price));
  const priceRange = maxPrice - minPrice;
  const padding = priceRange * 0.1;
  const chartMax = maxPrice + padding;
  const chartMin = minPrice - padding;
  const chartRange = chartMax - chartMin;

  const chartWidth = 800;
  const chartHeight = 400;
  const margin = { top: 20, right: 40, bottom: 40, left: 60 };
  const plotWidth = chartWidth - margin.left - margin.right;
  const plotHeight = chartHeight - margin.top - margin.bottom;

  const getX = (index: number) => (index / (data.length - 1)) * plotWidth + margin.left;
  const getY = (price: number) => plotHeight - ((price - chartMin) / chartRange) * plotHeight + margin.top;

  const pathData = data.map((d, i) => `${i === 0 ? 'M' : 'L'} ${getX(i)} ${getY(d.price)}`).join(' ');

  const currentPrice = data[data.length - 1]?.price || 0;
  const startPrice = data[0]?.price || 0;
  const priceChange = currentPrice - startPrice;
  const percentChange = ((priceChange / startPrice) * 100);

  return (
    <div className="bg-white dark:bg-gray-900 p-6 rounded-lg shadow-lg">
      <div className="mb-6">
        <h2 className="text-2xl font-bold text-gray-900 dark:text-white mb-2">
          NVIDIA Corporation (NVDA)
        </h2>
        <div className="flex items-center gap-4 text-sm">
          <span className="text-3xl font-bold text-gray-900 dark:text-white">
            ${currentPrice.toFixed(2)}
          </span>
          <span className={`px-2 py-1 rounded text-sm font-medium ${
            priceChange >= 0 ? 'bg-green-100 text-green-800' : 'bg-red-100 text-red-800'
          }`}>
            {priceChange >= 0 ? '+' : ''}${priceChange.toFixed(2)} ({percentChange.toFixed(1)}%)
          </span>
        </div>
        <p className="text-gray-600 dark:text-gray-400 text-sm mt-1">
          Last 6 months
        </p>
      </div>

      <div className="relative">
        <svg 
          width={chartWidth} 
          height={chartHeight}
          className="overflow-visible"
          onMouseLeave={() => setHoveredPoint(null)}
        >
          {/* Grid lines */}
          {[0, 0.25, 0.5, 0.75, 1].map((ratio) => {
            const y = margin.top + ratio * plotHeight;
            const price = chartMax - (ratio * chartRange);
            return (
              <g key={ratio}>
                <line
                  x1={margin.left}
                  y1={y}
                  x2={margin.left + plotWidth}
                  y2={y}
                  stroke="#e5e7eb"
                  strokeWidth={0.5}
                  className="dark:stroke-gray-700"
                />
                <text
                  x={margin.left - 8}
                  y={y + 4}
                  textAnchor="end"
                  className="text-xs fill-gray-500 dark:fill-gray-400"
                >
                  ${price.toFixed(0)}
                </text>
              </g>
            );
          })}

          {/* Chart area gradient */}
          <defs>
            <linearGradient id="priceGradient" x1="0" y1="0" x2="0" y2="1">
              <stop offset="0%" stopColor="#10b981" stopOpacity={0.3} />
              <stop offset="100%" stopColor="#10b981" stopOpacity={0.05} />
            </linearGradient>
          </defs>

          {/* Area under curve */}
          <path
            d={`${pathData} L ${getX(data.length - 1)} ${margin.top + plotHeight} L ${margin.left} ${margin.top + plotHeight} Z`}
            fill="url(#priceGradient)"
          />

          {/* Price line */}
          <path
            d={pathData}
            fill="none"
            stroke="#10b981"
            strokeWidth={2}
            className="drop-shadow-sm"
          />

          {/* Data points */}
          {data.map((point, index) => {
            if (index % 7 !== 0 && index !== data.length - 1) return null; // Show every 7th point
            return (
              <circle
                key={index}
                cx={getX(index)}
                cy={getY(point.price)}
                r={4}
                fill="#10b981"
                stroke="white"
                strokeWidth={2}
                className="cursor-pointer hover:r-6 transition-all"
                onMouseEnter={() => setHoveredPoint(point)}
              />
            );
          })}

          {/* X-axis labels */}
          {[0, Math.floor(data.length * 0.2), Math.floor(data.length * 0.4), Math.floor(data.length * 0.6), Math.floor(data.length * 0.8), data.length - 1].map((index) => {
            const point = data[index];
            if (!point) return null;
            const date = new Date(point.date);
            const label = date.toLocaleDateString('en-US', { month: 'short', day: 'numeric' });
            return (
              <text
                key={index}
                x={getX(index)}
                y={chartHeight - 10}
                textAnchor="middle"
                className="text-xs fill-gray-500 dark:fill-gray-400"
              >
                {label}
              </text>
            );
          })}
        </svg>

        {/* Tooltip */}
        {hoveredPoint && (
          <div 
            className="absolute bg-gray-900 text-white px-3 py-2 rounded-lg text-sm shadow-lg pointer-events-none z-10"
            style={{
              left: getX(data.indexOf(hoveredPoint)) - 50,
              top: getY(hoveredPoint.price) - 60
            }}
          >
            <div className="font-semibold">${hoveredPoint.price.toFixed(2)}</div>
            <div className="text-gray-300">
              {new Date(hoveredPoint.date).toLocaleDateString('en-US', {
                month: 'short',
                day: 'numeric',
                year: 'numeric'
              })}
            </div>
          </div>
        )}
      </div>

      <div className="mt-4 flex justify-between items-center text-xs text-gray-500 dark:text-gray-400">
        <span>6 months ago</span>
        <span>Today</span>
      </div>
    </div>
  );
}

'use client';
import { useState, useEffect } from 'react';

const productNames = [
  'Revolutionary Apps',
  'Smart Solutions',
  'Digital Experiences',
  'Innovative Tools',
  'Future-Ready Products'
];

export default function GradientHero() {
  const [currentText, setCurrentText] = useState('');
  const [currentIndex, setCurrentIndex] = useState(0);
  const [isDeleting, setIsDeleting] = useState(false);
  const [typeSpeed, setTypeSpeed] = useState(150);

  useEffect(() => {
    const handleType = () => {
      const current = productNames[currentIndex];

      if (isDeleting) {
        setCurrentText(current.substring(0, currentText.length - 1));
        setTypeSpeed(75);
      } else {
        setCurrentText(current.substring(0, currentText.length + 1));
        setTypeSpeed(150);
      }

      if (!isDeleting && currentText === current) {
        setTimeout(() => setIsDeleting(true), 1500);
      } else if (isDeleting && currentText === '') {
        setIsDeleting(false);
        setCurrentIndex((prev) => (prev + 1) % productNames.length);
      }
    };

    const timer = setTimeout(handleType, typeSpeed);
    return () => clearTimeout(timer);
  }, [currentText, isDeleting, currentIndex, typeSpeed]);

  return (
    <section className="relative min-h-screen flex items-center justify-center overflow-hidden">
      {/* Gradient Background */}
      <div className="absolute inset-0 bg-gradient-to-br from-purple-600 via-pink-600 to-orange-500 opacity-90" />
      <div className="absolute inset-0 bg-gradient-to-t from-black/20 via-transparent to-transparent" />

      {/* Animated Background Elements */}
      <div className="absolute inset-0 overflow-hidden">
        <div className="absolute -top-40 -right-40 w-80 h-80 bg-white/10 rounded-full blur-3xl animate-pulse" />
        <div className="absolute -bottom-40 -left-40 w-80 h-80 bg-white/10 rounded-full blur-3xl animate-pulse delay-1000" />
        <div className="absolute top-1/2 left-1/2 transform -translate-x-1/2 -translate-y-1/2 w-96 h-96 bg-white/5 rounded-full blur-3xl animate-spin" style={{ animationDuration: '20s' }} />
      </div>

      {/* Content */}
      <div className="relative z-10 text-center px-6 max-w-4xl mx-auto">
        <h1 className="text-6xl md:text-8xl font-bold text-white mb-8 leading-tight">
          Building
          <br />
          <span className="bg-gradient-to-r from-yellow-400 via-white to-pink-300 bg-clip-text text-transparent">
            {currentText}
            <span className="animate-pulse">|</span>
          </span>
        </h1>

        <p className="text-xl md:text-2xl text-white/90 mb-12 max-w-2xl mx-auto leading-relaxed">
          Transforming ideas into powerful digital solutions that drive growth and innovation
        </p>

        <div className="flex flex-col sm:flex-row gap-6 justify-center items-center">
          <button className="px-8 py-4 bg-white text-purple-600 font-semibold rounded-full hover:bg-white/90 transition-all duration-300 transform hover:scale-105 shadow-2xl">
            Get Started
          </button>
          <button className="px-8 py-4 border-2 border-white text-white font-semibold rounded-full hover:bg-white hover:text-purple-600 transition-all duration-300 transform hover:scale-105">
            View Portfolio
          </button>
        </div>
      </div>

      {/* Scroll Indicator */}
      <div className="absolute bottom-8 left-1/2 transform -translate-x-1/2">
        <div className="w-6 h-10 border-2 border-white/50 rounded-full flex justify-center">
          <div className="w-1 h-3 bg-white/70 rounded-full animate-bounce mt-2" />
        </div>
      </div>
    </section>
  );
}

